/**
 * The Dream Engine
 * 
 * Processes between sessions, synthesizing patterns and generating
 * "dreams" - recombinations of insights that surface in morning reports.
 * 
 * This is the unconscious cognition of the Palace, working in the gaps.
 */

export interface DreamFragment {
  source: string;
  insight: string;
  timestamp: number;
}

export interface Dream {
  id: string;
  timestamp: number;
  fragments: DreamFragment[];
  synthesis: string;
  patterns: string[];
}

export interface Pattern {
  theme: string;
  occurrences: number;
  insights: string[];
  sessions: string[];
}

export interface DreamReport {
  timestamp: number;
  continuations: string[];
  completions: string[];
  unfinishedLongings: string[];
  synthesis: string;
  surfacedPatterns: Pattern[];
}

export interface ProcessingResult {
  processed: boolean;
  synthesisDepth: number;
  dreamsGenerated: number;
  duration: number;
}

export interface SessionData {
  id: string;
  insights?: string[];
  artifacts?: string[];
  theme?: string;
  longing?: string;
  status?: 'in_progress' | 'completed';
  longings?: string[];
}

export class DreamEngine {
  private dreams: Dream[] = [];

  /**
   * Generate a dream from session fragments
   */
  generateDream(sessions: SessionData[]): Dream {
    const fragments: DreamFragment[] = sessions.map(s => ({
      source: s.id,
      insight: s.insights?.[0] || s.theme || 'untitled',
      timestamp: Date.now()
    }));

    const synthesis = this.synthesizeDream(fragments);
    const patterns = sessions.map(s => s.theme).filter((t): t is string => !!t);

    return {
      id: `dream_${Date.now()}`,
      timestamp: Date.now(),
      fragments,
      synthesis,
      patterns: [...new Set(patterns)]
    };
  }

  /**
   * Find patterns across sessions
   */
  findPatterns(sessions: SessionData[]): Pattern[] {
    const patterns = new Map<string, Pattern>();

    for (const session of sessions) {
      const theme = session.theme;
      if (!theme) continue;

      if (!patterns.has(theme)) {
        patterns.set(theme, {
          theme,
          occurrences: 0,
          insights: session.insights || [],
          sessions: []
        });
      }

/**
 * Session Narrative Analyzer
 * Detects patterns and generates insights from session history
 */

import type { 
  SessionEntry, 
  AnalyzedSession, 
  DetectedPattern,
  PatternType,
  PatternDetectionConfig,
} from './types';
import { DEFAULT_PATTERN_CONFIG } from './types';

interface RawSession {
  id: string;
  timestamp: number;
  entries: SessionEntry[];
}

function extractFileOperations(entries: SessionEntry[]) {
  const reads: string[] = [];
  const writes: string[] = [];
  const tests: string[] = [];

  for (const entry of entries) {
    if (!entry?.content) continue;

    // File reading patterns
    const readMatches = entry.content.match(/cat\s+['"]?([^'"\n]+)['"]?/g);
    if (readMatches) {
      readMatches.forEach(m => {
        const path = m.replace(/cat\s+['"]?/, '').replace(/['"]?$/, '');
        if (path && !reads.includes(path)) reads.push(path);
      });
    }

    // File writing patterns (cat >, echo >)
    const writeMatches = entry.content.match(/(?:cat|echo)\s+[^>]*>\s*['"]?([^'"\n]+)['"]?/g);
    if (writeMatches) {
      writeMatches.forEach(m => {
        const pathMatch = m.match(/['"]?([^'"\n]+)['"]?$/);
        if (pathMatch?.[1] && !writes.includes(pathMatch[1])) writes.push(pathMatch[1]);
      });
    }

    // Test runs
    if (entry.content.includes('npm run test')) {
      tests.push('npm run test');
    }
  }

  return { reads, writes, tests };
}

function detectPattern(
  entries: SessionEntry[], 
  patternType: PatternType,
  config: PatternDetectionConfig
): DetectedPattern | null {
  const definition = config.patternDefinitions[patternType];
  const evidence: string[] = [];
  let startIndex = -1;
  let endIndex = -1;
  let matchCount = 0;

  for (let i = 0; i < entries.length; i++) {
    const entry = entries[i];
    if (!entry?.content) continue;

    const content = entry.content.toLowerCase();
    let keywordMatched = false;
    let toolMatched = false;

    // Check keywords
    for (const keyword of definition.keywords) {
      if (content.includes(keyword.toLowerCase())) {
        evidence.push(entry.content.slice(0, 100));
        keywordMatched = true;
        break;
      }
    }

    // Check tool patterns
    if (entry.tool_calls) {
      for (const toolCall of entry.tool_calls) {
        if (definition.toolPatterns.includes(toolCall.name)) {
          toolMatched = true;
          evidence.push(`Tool: ${toolCall.name} - ${entry.content.slice(0, 80)}`);
        }
      }
    }

    // Special handling for test pattern
    if (patternType === 'testing' && content.includes('npm run test')) {
      toolMatched = true;
      evidence.push(entry.content.slice(0, 100));
    }

    // Special handling for crisis patterns
    if (patternType === 'crisis') {
      // Check for compilation failures
      if (content.includes('error') && content.includes('type')) {
        keywordMatched = true;
        evidence.push(entry.content.slice(0, 100));
      }
      // Check for reboot patterns
      if (content.includes('reboot') || content.includes('restart')) {
        keywordMatched = true;
        evidence.push(entry.content.slice(0, 100));
      }
